
CREATE DATABASE /*!32312 IF NOT EXISTS*/ `movie_website` /*!40100 DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci */ /*!80016 DEFAULT ENCRYPTION='N' */;

USE `movie_website`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `category` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(50) NOT NULL,
  `description` varchar(255) DEFAULT NULL,
  `sort_order` int DEFAULT '0',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;
INSERT INTO `category` VALUES (1,'动作','紧张刺激的动作电影',1,'2026-06-09 21:59:39'),(2,'喜剧','轻松搞笑的喜剧电影',2,'2026-06-09 21:59:39'),(3,'爱情','浪漫感人的爱情电影',3,'2026-06-09 21:59:39'),(4,'科幻','充满想象力的科幻电影',4,'2026-06-09 21:59:39'),(5,'动画','精彩纷呈的动画电影',5,'2026-06-09 21:59:39'),(6,'悬疑','扣人心弦的悬疑电影',6,'2026-06-09 21:59:39');
