INSERT INTO `crew` VALUES (1,'萨姆·门德斯','/tmdb_all_movie/1917/director/萨姆·门德斯.jpg','英国导演，奥斯卡得主，代表作《美国丽人》《1917》。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(2,'乔治·麦凯','/tmdb_all_movie/1917/actor/乔治·麦凯.jpg','英国新生代演员，凭借一战电影《1917》中的出色表演获得国际关注。',NULL,'ACTOR','2026-06-09 21:59:39'),(3,'安德鲁·斯科特','/tmdb_all_movie/1917/actor/安德鲁·斯科特.jpg','爱尔兰演员，在《神探夏洛克》中饰演莫里亚蒂教授，邪魅气质令人难忘。',NULL,'ACTOR','2026-06-09 21:59:39'),(4,'迪恩-查尔斯·查普曼','/tmdb_all_movie/1917/actor/迪恩-查尔斯·查普曼.jpg','英国童星，在《权力的游戏》中饰演托曼·拜拉席恩国王，虽然年幼但演技令人印象深刻。',NULL,'ACTOR','2026-06-09 21:59:39'),(5,'马克·斯特朗','/tmdb_all_movie/1917/actor/马克·斯特朗.jpg','英国演员，在《王牌特工》中饰演梅林，硬汉形象。',NULL,'ACTOR','2026-06-09 21:59:39'),(6,'王家卫','/tmdb_all_movie/2046/director/王家卫.jpg','香港国际导演，文艺片大师，代表作《花样年华》《重庆森林》《春光乍泄》。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(7,'巩俐','/tmdb_all_movie/2046/actor/巩俐.jpg','国际影后，张艺谋御用女主角，从《红高粱》到《霸王别姬》，享誉世界影坛。',NULL,'ACTOR','2026-06-09 21:59:39'),(8,'木村拓哉','/tmdb_all_movie/2046/actor/木村拓哉.jpg','日本国民偶像，SMAP成员，主演《悠长假期》《HERO》等超高收视日剧，影响了一个时代。',NULL,'ACTOR','2026-06-09 21:59:39'),(9,'梁朝伟','/tmdb_all_movie/2046/actor/梁朝伟.jpg','香港国际影帝，一双电眼迷倒万千观众，在《花样年华》中的表演堪称艺术。',NULL,'ACTOR','2026-06-09 21:59:39'),(10,'王菲','/tmdb_all_movie/2046/actor/王菲.jpg','华语乐坛天后，空灵的嗓音独树一帜，在《重庆森林》中展现了灵动的演技。',NULL,'ACTOR','2026-06-09 21:59:39'),(11,'叶念琛','/tmdb_all_movie/72家租客/director/叶念琛.jpg','香港导演，擅长爱情片，代表作《独家试爱》系列被称为爱情三部曲，刻画都市男女感情纠葛。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(12,'张学友','/tmdb_all_movie/72家租客/actor/张学友.jpg','香港歌神，四大天王之一，演唱过无数金曲，同时也是一位出色的电影演员。',NULL,'ACTOR','2026-06-09 21:59:39'),(13,'曾志伟','/tmdb_all_movie/72家租客/actor/曾志伟.jpg','香港资深演员兼主持人，出演过两百多部电影，从喜剧到正剧驾驭自如。',NULL,'ACTOR','2026-06-09 21:59:39'),(14,'袁咏仪','/tmdb_all_movie/72家租客/actor/袁咏仪.jpg','香港影后，在《新不了情》和《金枝玉叶》中连续两年获得香港金像奖影后。',NULL,'ACTOR','2026-06-09 21:59:39'),(15,'黄宗泽','/tmdb_all_movie/72家租客/actor/黄宗泽.jpg','香港演员，TVB当家小生，外形帅气，参演过《冲上云霄》等多部高收视港剧，深受观众喜爱。',NULL,'ACTOR','2026-06-09 21:59:39'),(16,'张坚庭','/tmdb_all_movie/97家有喜事/director/张坚庭.jpg','香港导演兼演员，执导过多部香港喜剧电影，也常在银幕中出演搞笑角色。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(17,'乔宏','/tmdb_all_movie/97家有喜事/actor/乔宏.jpg','香港已故资深演员，演技精湛，代表作《女人四十》展现了他深厚的表演功底。',NULL,'ACTOR','2026-06-09 21:59:39'),(18,'吴镇宇','/tmdb_all_movie/97家有喜事/actor/吴镇宇.jpg','香港影帝级演员，以邪气十足的表演风格著称，在《无间道2》中饰演倪永孝堪称经典。',NULL,'ACTOR','2026-06-09 21:59:39'),(19,'周星驰','/tmdb_all_movie/97家有喜事/actor/周星驰.jpg','香港喜剧之王，无厘头喜剧的开创者，从演员到导演都创造了无数经典。',NULL,'ACTOR','2026-06-09 21:59:39'),(20,'黄百鸣','/tmdb_all_movie/97家有喜事/actor/黄百鸣.jpg','香港电影人，开心鬼系列主演，新艺城创始人之一。',NULL,'ACTOR','2026-06-09 21:59:39'),(21,'成龙','/tmdb_all_movie/A计划/director/成龙.jpg','国际功夫巨星，奥斯卡终身成就奖得主，自导自演过多部经典动作喜剧。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(22,'元彪','/tmdb_all_movie/A计划/actor/元彪.jpg','香港动作演员，七小福成员，身手敏捷，代表作《快餐车》《飞龙猛将》等动作喜剧。',NULL,'ACTOR','2026-06-09 21:59:39'),(23,'洪金宝','/tmdb_all_movie/A计划/actor/洪金宝.jpg','香港功夫巨星，最灵活的胖子，动作导演界的泰斗，创立洪家班。',NULL,'ACTOR','2026-06-09 21:59:39'),(24,'狄威','/tmdb_all_movie/A计划/actor/狄威.jpg','香港动作演员，身手了得，参演过多部香港动作片，是洪家班成员之一。',NULL,'ACTOR','2026-06-09 21:59:39'),(25,'关之琳','/tmdb_all_movie/A计划续集/actor/关之琳.jpg','香港绝美女演员，在《黄飞鸿》系列中饰演十三姨，成为一代观众心中的女神。',NULL,'ACTOR','2026-06-09 21:59:39'),(26,'刘嘉玲','/tmdb_all_movie/A计划续集/actor/刘嘉玲.jpg','香港实力派女演员，梁朝伟妻子，代表作《阿飞正传》《无间道》《狄仁杰》系列。',NULL,'ACTOR','2026-06-09 21:59:39'),(27,'张曼玉','/tmdb_all_movie/A计划续集/actor/张曼玉.jpg','香港国际影后，从花瓶到影后的蜕变堪称传奇，在《花样年华》中的旗袍造型永恒经典。',NULL,'ACTOR','2026-06-09 21:59:39'),(28,'Michael Morris','/tmdb_all_movie/BJ单身日记4/director/Michael Morris.jpg','美国导演，执导过多部电视剧集，活跃于美国影视行业。',NULL,'DIRECTOR','2026-06-09 21:59:39'),(29,'休·格兰特','/tmdb_all_movie/BJ单身日记4/actor/休·格兰特.jpg','英国儒雅男神，凭借《四个婚礼和一个葬礼》《诺丁山》等浪漫喜剧成为全球偶像。',NULL,'ACTOR','2026-06-09 21:59:39'),(30,'切瓦特·埃加福','/tmdb_all_movie/BJ单身日记4/actor/切瓦特·埃加福.jpg','英国演员，凭借《为奴十二年》中的感人表演获得奥斯卡提名。',NULL,'ACTOR','2026-06-09 21:59:39'),(31,'利奥·伍德尔','/tmdb_all_movie/BJ单身日记4/actor/利奥·伍德尔.jpg','英国新生代演员，在《至暗时刻》中饰演丘吉尔的秘书受到关注。',NULL,'ACTOR','2026-06-09 21:59:39'),(32,'蕾妮·齐薇格','/tmdb_all_movie/BJ单身日记4/actor/蕾妮·齐薇格.jpg','美国奥斯卡影后，在《BJ单身日记》中饰演的布里吉特·琼斯成为经典角色。',NULL,'ACTOR','2026-06-09 21:59:39'),(33,'詹姆斯·麦克