INSERT INTO `movie` VALUES (1,'1917',NULL,NULL,'/tmdb_all_movie/1917/poster/1917.jpg','2019年英国一战史诗片，萨姆·门德斯导演。全片采用一镜到底拍摄手法，讲述两名士兵穿越战壕传递情报的惊险旅程，荣获奥斯卡最佳摄影等三项大奖。','2004-09-23',111,'美国',9.3,2952,'https://example.com/play/movie-1',0,597360,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(2,'2046',NULL,NULL,'/tmdb_all_movie/2046/poster/2046.jpg','2004年王家卫导演文艺经典，梁朝伟、章子怡主演。延续《花样年华》的故事线，在科幻与回忆的交织中讲述一个关于爱与遗忘的故事。','2016-07-02',146,'中国香港',8.0,15454,'https://example.com/play/movie-2',0,275501,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(3,'72家租客',NULL,NULL,'/tmdb_all_movie/72家租客/poster/72家租客.jpg','2010年香港贺岁喜剧，曾志伟导演，群星荟萃。致敬经典《72家房客》，讲述香港一栋大厦里租户与房东之间的爆笑故事。','2019-05-09',148,'中国香港',8.2,11969,'https://example.com/play/movie-3',0,574391,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(4,'97家有喜事',NULL,NULL,'/tmdb_all_movie/97家有喜事/poster/97家有喜事.jpg','1997年香港贺岁喜剧，周星驰、黄百鸣等主演。延续《家有喜事》的家族喜剧模式，搞笑桥段密集。','2014-04-05',121,'中国香港',6.7,13141,'https://example.com/play/movie-4',1,59343,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(5,'A计划',NULL,NULL,'/tmdb_all_movie/A计划/poster/A计划.jpg','1983年成龙自导自演经典动作喜剧。成龙饰演水警马如龙，跳钟楼一幕成为影史经典动作场面。','2007-08-01',130,'中国香港',7.1,15332,'https://example.com/play/movie-5',0,642320,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(6,'A计划续集',NULL,NULL,'/tmdb_all_movie/A计划续集/poster/A计划续集.jpg','1987年成龙自导自演续集。故事围绕水警与海盗的斗智斗勇展开，动作场面更加精彩。','2014-06-20',103,'中国香港',7.8,15354,'https://example.com/play/movie-6',0,466644,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(7,'BJ单身日记4',NULL,NULL,'/tmdb_all_movie/BJ单身日记4/poster/BJ单身日记4.jpg','布丽吉特·琼斯系列的延续，讲述这位英国剩女的爱情与生活。芮妮·齐薇格回归主演。','2012-09-20',147,'美国',8.8,10503,'https://example.com/play/movie-7',0,176035,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(8,'V字仇杀队',NULL,NULL,'/tmdb_all_movie/V字仇杀队/poster/V字仇杀队.jpg','2006年政治惊悚片，雨果·维文饰演戴着盖伊·福克斯面具的神秘革命者。探讨自由与极权主题，成为流行文化符号。','2006-11-11',110,'美国',7.9,13431,'https://example.com/play/movie-8',1,516496,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(9,'一代宗师',NULL,NULL,'/tmdb_all_movie/一代宗师/poster/一代宗师.jpg','2013年王家卫功夫史诗，梁朝伟、章子怡主演。以叶问为线索展现民国武林群像，章子怡凭此片横扫12个影后。','2001-04-03',102,'中国大陆',7.9,2903,'https://example.com/play/movie-9',0,100553,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(10,'一出好戏',NULL,NULL,'/tmdb_all_movie/一出好戏/poster/一出好戏.jpg','2018年黄渤自导自演荒诞喜剧。公司团建遭遇海难流落荒岛，上演人类社会演化寓言。','2020-05-20',103,'中国大陆',8.5,7075,'https://example.com/play/movie-10',0,282497,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(11,'七号房的礼物',NULL,NULL,'/tmdb_all_movie/七号房的礼物/poster/七号房的礼物.jpg','2013年韩国催泪片，智障父亲被冤入狱与女儿生离死别的故事。在狱友帮助下女儿悄悄进入监狱的桥段让人泪崩。','2011-11-10',126,'韩国',8.0,9681,'https://example.com/play/movie-11',0,350525,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(12,'七宗罪',NULL,NULL,'/tmdb_all_movie/七宗罪/poster/七宗罪.jpg','1995年大卫·芬奇导演经典犯罪惊悚片，布拉德·皮特、摩根·弗里曼主演。连环杀手以七宗罪为名惩罚罪犯的设定成为影史经典。','2015-07-15',116,'美国',6.5,4136,'https://example.com/play/movie-12',1,523698,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(13,'七年很痒',NULL,NULL,'/tmdb_all_movie/七年很痒/poster/七年很痒.jpg','1989年香港爱情喜剧，刘德华主演。讲述七年之痒的婚姻危机故事。','2014-03-04',145,'中国香港',9.2,6981,'https://example.com/play/movie-13',0,587412,1,1,'2026-06-09 21:59:39','2026-06-09 22:04:42'),(14,'三轮车夫',NULL,NULL,'/tmdb_all_movie/三轮车夫/poster/三轮车夫.jpg','1995年陈英雄导演越南电影，梁朝伟主演。讲述越南底层三轮车夫的生存挣扎。','2014-12-18',105,'越南',8.2,13553,'https://example.com/play/movie-14',0,615498,1,1,'2026-06-09 21:59:39','2026-06-09 22:02:08'),(15,'与神同行2：因与缘',NULL,NULL,'/tmdb_all_movie/与神同行2：因与缘/poster/与神同行2：因与缘.jpg','2018年奇幻续集，三位使者的前世今生揭晓，马东锡的家神承包笑点。','2014-06-09',108,'韩国',8.1,1217,'https://example.com/play/movie-15',0,409630,1,1,'2026-06-09 21:59:39','2026-06-09 22:01:45'),(16,'与神同行：罪与罚',NULL,NULL,'/tmdb_all_movie/与神同行：罪与罚/poster/与神同行：罪与罚.jpg','2017年韩国奇幻票房巨制，根据漫画改编。消防员死后在阴间接受七重审判的故事，特效精美情节催泪。','2009-06-09',112,'韩国',9.3,15283,'https://example.com/play/movie-16',1,343357,1,1,'2026-06-09 21:59:39','2026-06-09 22:01:45'),(17,'世界尽头',NULL,NULL,'/tmdb_all_movie/世界尽头/poster/世界尽头.jpg','2013年埃德加·赖特血与冰淇淋三部曲终章。五个中年男人试图完成年轻时未竟的酒吧巡游，却遇上外星人入侵。','2013-08-20',106,'英国',7.6,9